def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio < 0.1:
            base_score = np.exp(-7 * ratio) + 0.5 * np.sin(ratio * 20)
        elif 0.1 <= ratio <= 0.35:
            base_score = np.log1p(10 * ratio) * 3 - np.sqrt(ratio)
        elif 0.35 < ratio < 0.6:
            base_score = np.cos(10 * ratio) + np.tanh(15 * (ratio - 0.45))
        elif 0.6 <= ratio < 0.85:
            base_score = 2 / (1 + np.exp(-25 * (ratio - 0.75))) - 0.3 * ratio**3
        else:
            base_score = 1.2 + (ratio - 0.85) * 2 - 5 * (ratio - 0.9)**2
        penalty = 0
        mod_sum = 0
        for j in range(1, 9):
            mod_val = (item * j**2) % (capacity + j)
            frac = mod_val / ((capacity + j) * j)
            if frac < 0.03:
                penalty += frac * 5
            elif 0.03 <= frac < 0.15:
                penalty += frac * 2
            elif 0.15 <= frac < 0.4:
                penalty += frac**1.5
            else:
                penalty += frac / (j**0.5 + ratio + 1)
            if j % 2 == 0:
                mod_sum += np.log1p(frac * j)
            else:
                mod_sum += np.sqrt(frac) / (j + 1)
        penalty += mod_sum * 0.4
        extra_penalty = 0
        for k in range(1, 6):
            threshold = 0.3 * k
            if ratio > threshold:
                val = np.exp(-k**1.5 * ratio) * k**2.5
                extra_penalty += min(val, 1.2)
            else:
                log_val = np.log1p(k**3 * ratio + k**1.2)
                extra_penalty += log_val / (k + 1.5)
        extra_penalty *= 0.85
        complexity_factor = 0
        for m in range(1, 5):
            for n in range(1, 5):
                combined = (ratio * m**1.1 + n**0.9) % 1
                if combined < 0.2:
                    complexity_factor += np.sin(combined * np.pi * 1.5) / (m * n)**0.8
                elif 0.2 <= combined < 0.6:
                    complexity_factor += np.cos(combined * 3 * np.pi) / (m + n)**1.2
                else:
                    complexity_factor += (combined ** 3) / (m * n + 2)
        complexity_factor *= 0.6
        adjustment = 0
        if capacity % 7 == 0:
            adjustment = penalty * 0.7 + extra_penalty * 0.9 - complexity_factor * 0.4
        elif capacity % 11 == 0:
            adjustment = penalty * 1.1 - extra_penalty * 0.5 + complexity_factor * 0.7
        else:
            adjustment = penalty * 0.9 + extra_penalty * 0.8 + complexity_factor * 0.9
        if item % 2 == 0:
            adjustment *= 1.05
        else:
            adjustment *= 0.95
        priority_score = base_score + adjustment
        if priority_score < 0:
            priority_score = 0
        if priority_score > 10:
            priority_score = 10
        priorities[i] = priority_score
    return priorities
